+                    Text(this.presenter.inputKeyword.toString())
+                      .fontSize($r('sys.float.ohos_id_text_size_body2'))
+                      .fontColor(Color.Blue)
+                      .fontWeight(FontWeight.Medium)
+                      .margin({ bottom: $r('app.float.id_card_margin_sm') })
+                      .textOverflow({ overflow: TextOverflow.Ellipsis })
+                      .maxLines(2)
+                  }
+                } else if (this.item?.contact?.displayName.split(this.presenter.inputKeyword)
+                  .length - 1 !== idx) {
+                  Text(this.presenter.inputKeyword.toString())
+                    .fontSize($r('sys.float.ohos_id_text_size_body2'))
+                    .fontColor($r('sys.color.ohos_id_color_text_tertiary'))
+                    .fontWeight(FontWeight.Medium)
+                    .margin({ bottom: $r('app.float.id_card_margin_sm') })
+                    .textOverflow({ overflow: TextOverflow.Ellipsis })
+                    .maxLines(2)
+                }
+              }
+            })
+          }
+
+          Row() {
+            if (!StringUtil.isEmpty(this.item?.contact?.detailInfo) && '0' !== this.item?.contact?.hasPhoneNumber) {
+              ForEach(this.item?.contact?.detailInfo?.split(this.presenter.inputKeyword), (itemData: string, idx: number) => {
+                Row() {
+                  Text(itemData.toString())
+                    .fontSize($r('sys.float.ohos_id_text_size_body2'))
+                    .fontColor($r('sys.color.ohos_id_color_text_tertiary'))
+                    .fontWeight(FontWeight.Medium)
+                    .margin({ bottom: $r('app.float.id_card_margin_sm') })
+                    .textOverflow({ overflow: TextOverflow.Ellipsis })
+                    .maxLines(2)
+                  if (idx === 0) {
+                    if (this.item?.contact?.detailInfo.indexOf(this.presenter.inputKeyword) !== -1) {
+                      Text(this.presenter.inputKeyword.toString())
+                        .fontSize($r('sys.float.ohos_id_text_size_body2'))
+                        .fontColor(Color.Blue)
+                        .fontWeight(FontWeight.Medium)
+                        .margin({ bottom: $r('app.float.id_card_margin_sm') })
+                        .textOverflow({ overflow: TextOverflow.Ellipsis })
+                        .maxLines(2)
+                    }
+                  } else if (this.item?.contact?.detailInfo.split(this.presenter.inputKeyword)
+                    .length - 1 !== idx) {
+                    Text(this.presenter.inputKeyword.toString())
+                      .fontSize($r('sys.float.ohos_id_text_size_body2'))
+                      .fontColor($r('sys.color.ohos_id_color_text_tertiary'))
+                      .fontWeight(FontWeight.Medium)
+                      .margin({ bottom: $r('app.float.id_card_margin_sm') })
