+@Reusable
+@Component
+struct TelListItemWrapper {
+  @Prop private message: string;
+  @Link mPresenter: DetailPresenter;
+  @Link selectSimBuilder: SelectDialogBuilder;
+  @Prop private index: number;
+  @Prop telephoneTotal: number;
+  @Prop totalCount: number;
+  @Prop itemIndex: number;
+  @Prop moreOptionsFlag: boolean;
+  @Prop maximum: number;
+
+  isDividerShow(): Visibility {
+    let dividerShow: Visibility = Visibility.None;
+    if (!this.moreOptionsFlag && this.totalCount > this.maximum) {
+      if (this.itemIndex === this.maximum - 1) {
+        dividerShow = Visibility.None
+      } else {
+        dividerShow = Visibility.Visible
+      }
+    } else {
+      if (this.itemIndex === this.totalCount - 1) {
+        dividerShow = Visibility.None
+      } else {
+        dividerShow = Visibility.Visible
+      }
+    }
+    return dividerShow
+  }
+
+  build() {
+    Column() {
+      TelListItem({
+        message: this.message,
+        mPresenter: $mPresenter,
+        selectSimBuilder: $selectSimBuilder,
+        index: this.index,
+        telephoneTotal: this.telephoneTotal
+      })
+      Divider()
+        .color($r('app.color.skin_comp_divider'))
+        .strokeWidth('1px')
+        .width('100%')
+        .visibility(this.isDividerShow())
+        .padding({ left: $r('sys.float.padding_level4'), right: $r('sys.float.padding_level4') })
+    }
+  }
